import*as React from"react";import{AdaptivityContext,ViewWidth,ViewHeight}from"../components/AdaptivityProvider/AdaptivityContext";import{usePlatform}from"./usePlatform";import{VKCOM}from"../lib/platform";var useAdaptivity=function(){return React.useContext(AdaptivityContext)},useAdaptivityIsDesktop=function(){var t=usePlatform(),i=useAdaptivity(),e=i.viewWidth,o=i.viewHeight,i=i.hasMouse;return e>=ViewWidth.SMALL_TABLET&&(i||o>=ViewHeight.MEDIUM)||t===VKCOM};export{useAdaptivity,useAdaptivityIsDesktop};